example_code.after:
// PHP 8.4: property hooks eliminate boilerplate
class MoneyDTO
{
    public int $cents {
        set(int $value) {
            if ($value < 0) {
                throw new \InvalidArgumentException('Amount cannot be negative');
            }
            $this->cents = $value;
        }
    }

    public float $dollars {
        get => $this->cents / 100;
    }

    public function __construct(int $cents)
    {
        $this->cents = $cents; // triggers the set hook
    }
}

